import React from 'react';

function TableTemplate({ data, columns, entityIdKey, onEdit, onDelete }) {
  if (!data || data.length === 0) {
    return <p>No records found.</p>;
  }

  return (
    <table border="1" style={{ width: '100%', borderCollapse: 'collapse', marginTop: '20px' }}>
      <thead>
        <tr>
          {columns.map(col => (
            <th key={col.key} style={{ padding: '8px', background: '#f2f2f2' }}>
              {col.header}
            </th>
          ))}
          <th style={{ padding: '8px', background: '#f2f2f2' }}>Actions</th>
        </tr>
      </thead>
      <tbody>
        {data.map(item => (
          <tr key={item[entityIdKey]}>
            {columns.map(col => (
              <td key={col.key} style={{ padding: '8px' }}>
                {/* Display N/A for null values */}
                {item[col.key] === null || item[col.key] === undefined ? 'N/A' : item[col.key]}
              </td>
            ))}
            <td style={{ padding: '8px' }}>
              <button onClick={() => onEdit(item)} style={{ marginRight: '10px' }}>Edit</button>
              <button onClick={() => onDelete(item[entityIdKey])} style={{ color: 'red' }}>Delete</button>
            </td>
          </tr>
        ))}
      </tbody>
    </table>
  );
}

export default TableTemplate;
